package com.example.offlineshapealarm.alarm
import android.content.*; import android.os.Build; import android.util.Log
class AlarmReceiver: BroadcastReceiver(){ override fun onReceive(context: Context, intent: Intent){ if(intent.action!=AlarmScheduling.ACTION_FIRE) return; val payload=runCatching{AlarmPayload.fromJson(intent.getStringExtra(AlarmScheduling.EXTRA_PAYLOAD) ?: return)}.getOrElse{ Log.w("ShapeAlarm","Invalid alarm payload",it); return }; Log.d("ShapeAlarm","Alarm triggered ${payload.alarmId}"); if(payload.repeatDays.isNotEmpty()){ nextTriggerMillis(payload)?.let{ AlarmScheduling.schedule(context, payload.copy(triggerAtEpochMillis=it), true); Log.d("ShapeAlarm","Next recurrence scheduled ${payload.alarmId} at $it") } } else AlarmRegistry(context).remove(payload.alarmId); val svc=Intent(context, AlarmForegroundService::class.java).setAction(AlarmForegroundService.ACTION_START_ALARM).putExtra(AlarmScheduling.EXTRA_PAYLOAD,payload.toJson()); if(Build.VERSION.SDK_INT>=26) context.startForegroundService(svc) else context.startService(svc) } }
